const items = $input.all();
const byModel = {};
for (const item of items) {
  const d = item.json;
  const key = d.modelLabel;
  if (!byModel[key]) {
    byModel[key] = { modelLabel: d.modelLabel, modelSlug: d.modelSlug, providerPinned: d.providerPinned, providerActual: d.providerActual, modelActual: d.modelActual, answers: [] };
  }
  byModel[key].answers.push({ questionId: d.questionId, topic: d.topic, question: d.question, response: d.response, totalTokens: (d.promptTokens || 0) + (d.completionTokens || 0) });
}
for (const key of Object.keys(byModel)) {
  byModel[key].answers.sort((a, b) => a.questionId - b.questionId);
}
return [{ json: { runAt: new Date().toISOString(), totalResponses: items.length, modelsRan: Object.keys(byModel).length, results: Object.values(byModel) } }];
